import type { ComponentProps, ComponentRef } from 'react';
import { Combobox as ComboboxPrimitive } from '@base-ui/react/combobox';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import {
  CheckIcon,
  ChevronDownIcon,
  ChevronUpDownIcon,
  CloseIcon,
  PopupArrowIcon,
} from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Combobox.module.css';

type IndicatorPosition = 'start' | 'end' | 'none';
type ComboboxContentProps = ComboboxPrimitive.Popup.Props &
  Pick<
    ComboboxPrimitive.Positioner.Props,
    | 'side'
    | 'sideOffset'
    | 'align'
    | 'alignOffset'
    | 'arrowPadding'
    | 'collisionAvoidance'
    | 'collisionBoundary'
    | 'collisionPadding'
  > & {
    showArrow?: boolean;
  };

const COMBOBOX_CONTENT_SIDE_OFFSET = 5;

const Combobox = ComboboxPrimitive.Root;

function ComboboxField({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="combobox-field" className={clsx(styles.field, className)} {...props} />;
}

const ComboboxFieldLabel = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Label>,
  ComboboxPrimitive.Label.Props
>(function ComboboxFieldLabel({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Label
      ref={ref}
      data-slot="combobox-field-label"
      className={mergeClassName(className, styles.fieldLabel)}
      {...props}
    />
  );
});

function ComboboxValue(props: ComboboxPrimitive.Value.Props) {
  return <ComboboxPrimitive.Value data-slot="combobox-value" {...props} />;
}

const ComboboxInlineInputContainer = forwardRef<HTMLDivElement, ComponentProps<'div'>>(
  function ComboboxInlineInputContainer({ className, ...props }, ref) {
    return (
      <div
        ref={ref}
        data-slot="combobox-inline-input-container"
        className={clsx(styles.inlineInputContainer, className)}
        {...props}
      />
    );
  },
);

const ComboboxInputGroup = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.InputGroup>,
  ComboboxPrimitive.InputGroup.Props
>(function ComboboxInputGroup({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.InputGroup
      ref={ref}
      data-slot="combobox-input-group"
      className={mergeClassName(className, styles.inputGroup)}
      {...props}
    />
  );
});

const ComboboxInput = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Input>,
  ComboboxPrimitive.Input.Props
>(function ComboboxInput({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Input
      ref={ref}
      data-slot="combobox-input"
      className={mergeClassName(className, styles.input)}
      {...props}
    />
  );
});

function ComboboxControlActions({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div
      data-slot="combobox-control-actions"
      className={clsx(styles.controlActions, className)}
      {...props}
    />
  );
}

const ComboboxTrigger = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Trigger>,
  ComboboxPrimitive.Trigger.Props
>(function ComboboxTrigger({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.Trigger
      ref={ref}
      data-slot="combobox-trigger"
      className={mergeClassName(className, styles.trigger)}
      {...props}
    >
      {children ?? <ChevronDownIcon className={styles.iconSvg} />}
    </ComboboxPrimitive.Trigger>
  );
});

const ComboboxFieldTrigger = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Trigger>,
  ComboboxPrimitive.Trigger.Props
>(function ComboboxFieldTrigger({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Trigger
      ref={ref}
      data-slot="combobox-field-trigger"
      className={mergeClassName(className, styles.fieldTrigger)}
      {...props}
    />
  );
});

const ComboboxIcon = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Icon>,
  ComboboxPrimitive.Icon.Props
>(function ComboboxIcon({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.Icon
      ref={ref}
      data-slot="combobox-icon"
      className={mergeClassName(className, styles.icon)}
      {...props}
    >
      {children ?? <ChevronUpDownIcon className={styles.iconSvg} />}
    </ComboboxPrimitive.Icon>
  );
});

const ComboboxClear = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Clear>,
  ComboboxPrimitive.Clear.Props
>(function ComboboxClear({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.Clear
      ref={ref}
      data-slot="combobox-clear"
      className={mergeClassName(className, styles.clear)}
      {...props}
    >
      {children ?? <CloseIcon className={styles.iconSvg} />}
    </ComboboxPrimitive.Clear>
  );
});

const ComboboxPortal = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Portal>,
  ComboboxPrimitive.Portal.Props
>(function ComboboxPortal({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Portal
      ref={ref}
      data-slot="combobox-portal"
      className={className}
      {...props}
    />
  );
});

const ComboboxBackdrop = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Backdrop>,
  ComboboxPrimitive.Backdrop.Props
>(function ComboboxBackdrop({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Backdrop
      ref={ref}
      data-slot="combobox-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
});

const ComboboxPositioner = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Positioner>,
  ComboboxPrimitive.Positioner.Props
>(function ComboboxPositioner({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Positioner
      ref={ref}
      data-slot="combobox-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
});

const ComboboxPopup = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Popup>,
  ComboboxPrimitive.Popup.Props
>(function ComboboxPopup({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Popup
      ref={ref}
      data-slot="combobox-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
});

const ComboboxArrow = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Arrow>,
  ComboboxPrimitive.Arrow.Props
>(function ComboboxArrow({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.Arrow
      ref={ref}
      data-slot="combobox-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? <ArrowSvg className={styles.arrowSvg} />}
    </ComboboxPrimitive.Arrow>
  );
});

const ComboboxContent = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Popup>,
  ComboboxContentProps
>(function ComboboxContent(
  {
    className,
    showArrow = false,
    children,
    side,
    sideOffset = COMBOBOX_CONTENT_SIDE_OFFSET,
    align,
    alignOffset,
    arrowPadding,
    collisionAvoidance,
    collisionBoundary,
    collisionPadding,
    ...props
  },
  ref,
) {
  return (
    <ComboboxPortal>
      <ComboboxPositioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        arrowPadding={arrowPadding}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <ComboboxPopup ref={ref} className={className} {...props}>
          {showArrow ? <ComboboxArrow /> : null}
          {children}
        </ComboboxPopup>
      </ComboboxPositioner>
    </ComboboxPortal>
  );
});

const ComboboxStatus = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Status>,
  ComboboxPrimitive.Status.Props
>(function ComboboxStatus({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Status
      ref={ref}
      data-slot="combobox-status"
      className={mergeClassName(className, styles.status)}
      {...props}
    />
  );
});

const ComboboxEmpty = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Empty>,
  ComboboxPrimitive.Empty.Props
>(function ComboboxEmpty({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Empty
      ref={ref}
      data-slot="combobox-empty"
      className={mergeClassName(className, styles.empty)}
      {...props}
    />
  );
});

const ComboboxList = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.List>,
  ComboboxPrimitive.List.Props
>(function ComboboxList({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.List
      ref={ref}
      data-slot="combobox-list"
      className={mergeClassName(className, styles.list)}
      {...props}
    />
  );
});

const ComboboxRow = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Row>,
  ComboboxPrimitive.Row.Props
>(function ComboboxRow({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Row
      ref={ref}
      data-slot="combobox-row"
      className={mergeClassName(className, styles.row)}
      {...props}
    />
  );
});

const ComboboxItem = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Item>,
  ComboboxPrimitive.Item.Props & {
    indicator?: IndicatorPosition;
  }
>(function ComboboxItem({ className, indicator, ...props }, ref) {
  return (
    <ComboboxPrimitive.Item
      ref={ref}
      data-slot="combobox-item"
      data-indicator-position={indicator}
      className={mergeClassName(className, styles.item)}
      {...props}
    />
  );
});

const ComboboxItemIndicator = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemIndicator>,
  ComboboxPrimitive.ItemIndicator.Props
>(function ComboboxItemIndicator({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemIndicator
      ref={ref}
      data-slot="combobox-item-indicator"
      className={mergeClassName(className, styles.itemIndicator)}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </ComboboxPrimitive.ItemIndicator>
  );
});

function ComboboxItemText({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span data-slot="combobox-item-text" className={clsx(styles.itemText, className)} {...props} />
  );
}

const ComboboxSeparator = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Separator>,
  ComboboxPrimitive.Separator.Props
>(function ComboboxSeparator({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Separator
      ref={ref}
      data-slot="combobox-separator"
      className={mergeClassName(className, styles.separator)}
      {...props}
    />
  );
});

const ComboboxGroup = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Group>,
  ComboboxPrimitive.Group.Props
>(function ComboboxGroup({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Group
      ref={ref}
      data-slot="combobox-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
});

const ComboboxGroupLabel = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.GroupLabel>,
  ComboboxPrimitive.GroupLabel.Props
>(function ComboboxGroupLabel({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.GroupLabel
      ref={ref}
      data-slot="combobox-group-label"
      className={mergeClassName(className, styles.groupLabel)}
      {...props}
    />
  );
});

function ComboboxCollection(props: ComboboxPrimitive.Collection.Props) {
  return <ComboboxPrimitive.Collection data-slot="combobox-collection" {...props} />;
}

const ComboboxChips = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Chips>,
  ComboboxPrimitive.Chips.Props
>(function ComboboxChips({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Chips
      ref={ref}
      data-slot="combobox-chips"
      className={mergeClassName(className, styles.chips)}
      {...props}
    />
  );
});

const ComboboxChip = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Chip>,
  ComboboxPrimitive.Chip.Props
>(function ComboboxChip({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Chip
      ref={ref}
      data-slot="combobox-chip"
      className={mergeClassName(className, styles.chip)}
      {...props}
    />
  );
});

const ComboboxChipRemove = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ChipRemove>,
  ComboboxPrimitive.ChipRemove.Props
>(function ComboboxChipRemove({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.ChipRemove
      ref={ref}
      data-slot="combobox-chip-remove"
      className={mergeClassName(className, styles.chipRemove)}
      {...props}
    >
      {children ?? <CloseIcon className={styles.chipRemoveIcon} />}
    </ComboboxPrimitive.ChipRemove>
  );
});

function ComboboxChipText({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span data-slot="combobox-chip-text" className={clsx(styles.chipText, className)} {...props} />
  );
}

const ComboboxChipsInput = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Input>,
  ComboboxPrimitive.Input.Props
>(function ComboboxChipsInput({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Input
      ref={ref}
      data-slot="combobox-chips-input"
      className={mergeClassName(className, styles.chipsInput)}
      {...props}
    />
  );
});

const useComboboxFilter = ComboboxPrimitive.useFilter;
const useComboboxFilteredItems = ComboboxPrimitive.useFilteredItems;

function ArrowSvg(props: ComponentProps<'svg'>) {
  return (
    <PopupArrowIcon
      fillClassName={styles.arrowFill}
      outerStrokeClassName={styles.arrowOuterStroke}
      innerStrokeClassName={styles.arrowInnerStroke}
      {...props}
    />
  );
}

export {
  Combobox,
  ComboboxField,
  ComboboxFieldLabel,
  ComboboxValue,
  ComboboxInlineInputContainer,
  ComboboxInputGroup,
  ComboboxInput,
  ComboboxControlActions,
  ComboboxTrigger,
  ComboboxFieldTrigger,
  ComboboxIcon,
  ComboboxClear,
  ComboboxPortal,
  ComboboxBackdrop,
  ComboboxPositioner,
  ComboboxPopup,
  ComboboxContent,
  ComboboxArrow,
  ComboboxStatus,
  ComboboxEmpty,
  ComboboxList,
  ComboboxRow,
  ComboboxItem,
  ComboboxItemIndicator,
  ComboboxItemText,
  ComboboxSeparator,
  ComboboxGroup,
  ComboboxGroupLabel,
  ComboboxCollection,
  ComboboxChips,
  ComboboxChip,
  ComboboxChipRemove,
  ComboboxChipText,
  ComboboxChipsInput,
  useComboboxFilter,
  useComboboxFilteredItems,
};

@layer ui.components {
  .fieldLabel {
    display: inline-flex;
    align-items: center;
    font-size: var(--combobox-label-font-size, var(--text-sm));
    line-height: var(--combobox-label-line-height, var(--line-height-text-sm));
    font-weight: var(--combobox-label-font-weight, var(--weight-medium));
    color: var(--combobox-color, var(--color-foreground));
    cursor: default;
  }

  .inputGroup {
    position: relative;
    display: flex;
    align-items: center;
    width: var(--combobox-width, 16rem);
    min-height: var(--combobox-control-height, var(--size-lg));
    padding-inline: var(--combobox-input-group-padding-x, 0);
    border: var(--combobox-border-width, var(--border-width-sm)) solid
      var(--combobox-border-color, var(--color-border));
    border-radius: var(--combobox-radius, var(--radius-md));
    background-color: var(--combobox-bg, var(--color-background));
    color: var(--combobox-color, var(--color-foreground));
    outline: var(--combobox-border-width, var(--border-width-sm)) solid transparent;
    outline-offset: calc(var(--combobox-border-width, var(--border-width-sm)) * -1);
    transition:
      border-color var(--transition-default),
      outline-color var(--transition-default);

    &:focus-within {
      border-color: var(--combobox-focus-ring-color, var(--color-ring));
      outline-color: var(--combobox-focus-ring-color, var(--color-ring));
    }

    &:has(> [data-slot='combobox-input'][data-disabled], > [data-slot='combobox-input']:disabled) {
      opacity: var(--opacity-disabled);
    }
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    height: var(--combobox-control-height, var(--size-lg));
    margin: 0;
    border: 0;
    border-radius: inherit;
    padding-inline: var(--combobox-input-padding-x-start, 0.875rem)
      var(--combobox-input-padding-x-end, 3.25rem);
    background: transparent;
    color: inherit;
    font: inherit;
    outline: 0;

    &::placeholder {
      color: var(--combobox-input-placeholder-color, var(--color-muted-foreground));
    }
  }

  .trigger,
  .clear {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--combobox-action-size, 1.5rem);
    height: var(--combobox-action-size, 1.5rem);
    flex-shrink: 0;
    margin: 0;
    padding: 0;
    border: 0;
    border-radius: var(--combobox-action-radius, var(--radius-sm));
    background: var(--combobox-action-bg, transparent);
    color: var(--combobox-icon-color, var(--color-muted-foreground));
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      color var(--transition-default);

    &:hover:not(:disabled):not([data-disabled]) {
      background-color: var(--combobox-action-bg-hover, var(--color-muted));
      color: var(--combobox-action-color-hover, var(--color-foreground));
    }

    &:focus-visible {
      outline: var(--border-width-sm) solid var(--combobox-focus-ring-color, var(--color-ring));
      outline-offset: var(--border-width-sm);
    }

    &:is(:disabled, [data-disabled]) {
      cursor: not-allowed;
    }
  }

  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--combobox-icon-size, 0.875rem);
    height: var(--combobox-icon-size, 0.875rem);
    flex-shrink: 0;
    color: var(--combobox-icon-color, var(--color-muted-foreground));
  }

  .iconSvg {
    width: var(--combobox-icon-svg-size, 1rem);
    height: var(--combobox-icon-svg-size, 1rem);
  }

  .fieldTrigger {
    display: inline-flex;
    width: var(--combobox-width, 16rem);
    min-height: var(--combobox-control-height, var(--size-lg));
    align-items: center;
    justify-content: space-between;
    gap: 0.75rem;
    padding: 0 0.875rem;
    border: var(--combobox-border-width, var(--border-width-sm)) solid
      var(--combobox-border-color, var(--color-border));
    border-radius: var(--combobox-radius, var(--radius-md));
    background-color: var(--combobox-bg, var(--color-background));
    color: var(--combobox-color, var(--color-foreground));
    outline: var(--combobox-border-width, var(--border-width-sm)) solid transparent;
    outline-offset: calc(var(--combobox-border-width, var(--border-width-sm)) * -1);
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      outline-color var(--transition-default);

    &[data-popup-open] {
      background-color: var(--color-muted);
    }

    &:focus-visible {
      border-color: var(--combobox-focus-ring-color, var(--color-ring));
      outline-color: var(--combobox-focus-ring-color, var(--color-ring));
    }

    &:is([disabled], [data-disabled]) {
      opacity: var(--opacity-disabled);
      cursor: not-allowed;
    }
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--combobox-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--combobox-backdrop-blur, 4px)));
    transition:
      opacity var(--combobox-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--combobox-backdrop-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--combobox-backdrop-starting-opacity, 0);
      backdrop-filter: var(--combobox-backdrop-starting-blur, none);
    }

    &[data-ending-style] {
      opacity: var(--combobox-backdrop-ending-opacity, 0);
      backdrop-filter: var(--combobox-backdrop-ending-blur, none);
    }
  }

  .positioner {
    z-index: var(--z-popup);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    width: var(--anchor-width);
    min-width: min(var(--anchor-width), var(--available-width));
    max-width: var(--available-width);
    max-height: min(var(--combobox-popup-max-height, 24rem), var(--available-height));
    overflow: visible;
    border: 0;
    border-radius: var(--combobox-radius, var(--radius-md));
    background-color: var(--combobox-popup-bg, var(--color-popover));
    color: var(--combobox-color, var(--color-popover-foreground));
    outline: var(--border-width-sm) solid var(--combobox-popup-border-color, var(--color-border));
    box-shadow: var(--combobox-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      opacity var(--combobox-popup-transition, var(--transition-default)),
      transform var(--combobox-popup-transition, var(--transition-default)),
      translate var(--combobox-popup-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--combobox-popup-starting-opacity, 0);
      translate: var(--combobox-popup-starting-translate-x, 0)
        var(--combobox-popup-starting-translate-y, 0);
      transform: scale(var(--combobox-popup-starting-scale, var(--scale-popup)));
    }

    &[data-ending-style] {
      opacity: var(--combobox-popup-ending-opacity, 0);
      translate: var(--combobox-popup-ending-translate-x, 0)
        var(--combobox-popup-ending-translate-y, 0);
      transform: scale(var(--combobox-popup-ending-scale, var(--scale-popup)));
    }
  }

  .arrow {
    display: flex;
    color: var(--combobox-popup-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--combobox-arrow-size, 8px) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--combobox-arrow-size, 8px) * -1);
      rotate: 0deg;
    }

    &[data-side='left'] {
      right: calc(var(--combobox-arrow-inline-offset, 13px) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--combobox-arrow-inline-offset, 13px) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--combobox-arrow-width, 1.25rem);
    height: var(--combobox-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(
      --combobox-arrow-stroke-color,
      var(--combobox-popup-border-color, var(--color-border))
    );
  }

  .arrowInnerStroke {
    fill: var(--combobox-popup-bg, var(--color-popover));
  }

  .status {
    margin: 0;

    &:not(:empty) {
      display: flex;
      align-items: center;
      gap: var(--combobox-status-gap, var(--spacing-1));
      padding: var(--combobox-status-padding-y, 0.5rem) var(--combobox-status-padding-x, 0.75rem);
      border-bottom: var(--combobox-status-divider-width, var(--border-width-sm)) solid
        var(
          --combobox-status-divider-color,
          var(--combobox-popup-border-color, var(--color-border))
        );
      font-size: var(--combobox-status-font-size, var(--text-xs));
      line-height: var(--combobox-status-line-height, var(--line-height-text-xs));
      color: var(
        --combobox-status-color,
        var(--combobox-empty-color, var(--color-muted-foreground))
      );
    }
  }

  .empty {
    margin: 0;

    &:not(:empty) {
      padding: var(--combobox-empty-padding-y, 0.75rem) var(--combobox-empty-padding-x, 1rem);
      font-size: var(--combobox-empty-font-size, var(--text-sm));
      line-height: var(--combobox-empty-line-height, var(--line-height-text-sm));
      color: var(--combobox-empty-color, var(--color-muted-foreground));
    }
  }

  .list {
    box-sizing: border-box;
    max-height: min(
      var(--combobox-list-max-height, var(--combobox-popup-max-height, 24rem)),
      var(--available-height)
    );
    overflow-y: auto;
    overscroll-behavior: contain;
    padding-block: var(--combobox-list-padding-y, var(--popup-list-padding-y, 0.25rem));
    scroll-padding-block: var(
      --combobox-list-scroll-padding-y,
      var(--popup-list-padding-y, 0.25rem)
    );
    outline: 0;

    &[data-empty] {
      padding: 0;
    }
  }

  .row {
    display: contents;
  }

  .item {
    box-sizing: border-box;
    position: relative;
    display: grid;
    grid-template-columns:
      var(--combobox-item-indicator-size, var(--popup-check-indicator-size, 0.75rem))
      minmax(0, 1fr);
    align-items: center;
    gap: var(--combobox-item-gap, var(--spacing-2));
    min-height: var(--combobox-item-min-height, var(--popup-item-min-height, 2rem));
    width: 100%;
    padding-block: var(--combobox-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(
        --combobox-check-padding-x-start,
        var(--popup-check-padding-x-start, 0.625rem)
      )
      var(--combobox-item-padding-x-end, var(--popup-item-padding-x-end, 1rem));
    border: var(--combobox-item-border-width, 0) solid
      var(--combobox-item-border-color, transparent);
    border-radius: var(--combobox-item-border-radius, 0);
    background-color: var(--combobox-item-bg, transparent);
    outline: 0;
    cursor: default;
    user-select: none;
    font: inherit;
    font-size: var(--combobox-item-font-size, var(--popup-item-font-size, var(--text-sm)));
    line-height: var(
      --combobox-item-line-height,
      var(--popup-item-line-height, var(--line-height-text-sm))
    );
    color: var(--combobox-item-color, var(--combobox-color, var(--color-foreground)));

    &[data-highlighted] {
      z-index: 0;
      color: var(--combobox-highlight-color, var(--color-background));
    }

    &[data-highlighted]::before {
      content: '';
      position: absolute;
      z-index: -1;
      inset-block: 0;
      inset-inline: var(
        --combobox-highlight-inset-x,
        var(--popup-highlight-inset-x, var(--spacing-1))
      );
      border-radius: var(
        --combobox-highlight-radius,
        var(--popup-highlight-radius, var(--radius-sm))
      );
      background-color: var(--combobox-highlight-bg, var(--color-foreground));
    }

    &[data-disabled] {
      opacity: var(--opacity-disabled);
      pointer-events: none;
    }

    &[data-indicator-position='none'] {
      grid-template-columns: minmax(0, 1fr);
      padding-inline-start: var(
        --combobox-item-padding-x-start,
        var(--popup-item-padding-x-start, 1rem)
      );

      & > .itemIndicator {
        display: none;
      }

      & > .itemText {
        grid-column-start: 1;
      }
    }

    &[data-indicator-position='end'] {
      grid-template-columns:
        minmax(0, 1fr)
        var(--combobox-item-indicator-size, var(--popup-check-indicator-size, 0.75rem));

      & > .itemIndicator {
        grid-column-start: 2;
        justify-self: end;
      }

      & > .itemText {
        grid-column-start: 1;
      }
    }
  }

  .itemIndicator {
    grid-column-start: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: var(--combobox-item-indicator-padding, 0);
    width: var(--combobox-item-indicator-size, var(--popup-check-indicator-size, 0.75rem));
    height: var(--combobox-item-indicator-size, var(--popup-check-indicator-size, 0.75rem));
    border: var(--combobox-item-indicator-border-width, 0) solid
      var(--combobox-item-indicator-border-color, transparent);
    border-radius: var(--combobox-item-indicator-radius, 0);
    background-color: var(--combobox-item-indicator-bg, transparent);
  }

  .itemIndicatorIcon {
    width: var(--combobox-item-indicator-icon-size, 0.75rem);
    height: var(--combobox-item-indicator-icon-size, 0.75rem);
  }

  .separator {
    height: var(--border-width-sm);
    margin: var(--combobox-separator-margin-y, var(--popup-separator-margin-y, 0.375rem))
      var(--combobox-separator-margin-x, var(--popup-separator-margin-x-start, 1rem));
    background-color: var(--combobox-border-color, var(--color-border));
  }

  .group {
    padding-bottom: var(--combobox-group-padding-bottom, var(--spacing-1));
  }

  .groupLabel {
    position: sticky;
    top: 0;
    z-index: 1;
    display: block;
    margin: 0;
    padding: var(--combobox-group-label-padding-top, var(--popup-group-label-padding-y, 0.35rem))
      var(--combobox-group-label-padding-x, var(--popup-group-label-padding-x-start, 0.625rem))
      var(--combobox-group-label-padding-bottom, var(--popup-group-label-padding-y, 0.35rem));
    background-color: var(
      --combobox-group-label-bg,
      var(--combobox-popup-bg, var(--color-popover))
    );
    color: var(--combobox-group-label-color, var(--color-muted-foreground));
    font-size: var(
      --combobox-group-label-font-size,
      var(--popup-group-label-font-size, var(--text-xs))
    );
    font-weight: var(--combobox-group-label-font-weight, var(--weight-semibold));
    line-height: var(
      --combobox-group-label-line-height,
      var(--popup-group-label-line-height, var(--line-height-text-xs))
    );
  }

  .chips {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--combobox-chips-gap, var(--spacing-1));
    width: 100%;
    padding: var(--combobox-chips-padding, var(--spacing-1));
    cursor: text;
  }

  .chip {
    display: inline-flex;
    align-items: center;
    gap: var(--combobox-chip-gap, var(--spacing-1));
    min-height: var(--combobox-chip-min-height, 1.625rem);
    max-width: 100%;
    padding: var(--combobox-chip-padding-y, 0.1875rem) var(--combobox-chip-padding-right, 0.375rem)
      var(--combobox-chip-padding-y, 0.1875rem) var(--combobox-chip-padding-left, 0.5rem);
    border-radius: var(--combobox-chip-radius, var(--radius-sm));
    background: var(--combobox-chip-bg, var(--color-muted));
    color: var(--combobox-chip-color, var(--color-foreground));
    font-size: var(--combobox-chip-font-size, var(--text-sm));
    line-height: var(--combobox-chip-line-height, var(--line-height-text-sm));

    &[data-highlighted] {
      background-color: var(--combobox-highlight-bg, var(--color-accent));
      color: var(--combobox-highlight-color, var(--color-accent-foreground));
    }

    &:has([disabled]) {
      opacity: var(--opacity-disabled);
      pointer-events: none;
    }
  }

  .chipRemove {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--combobox-chip-remove-size, 1rem);
    height: var(--combobox-chip-remove-size, 1rem);
    margin: 0;
    padding: 0;
    border: 0;
    border-radius: var(--combobox-chip-remove-radius, var(--radius-sm));
    background: transparent;
    color: inherit;
    cursor: pointer;

    &:hover {
      background-color: var(--combobox-chip-remove-bg-hover, var(--color-overlay-foreground));
    }
  }

  .chipRemoveIcon {
    width: var(--combobox-chip-remove-icon-size, 0.75rem);
    height: var(--combobox-chip-remove-icon-size, 0.75rem);
  }

  .chipsInput {
    flex: 1 1 var(--combobox-chips-input-min-width, 4rem);
    min-width: var(--combobox-chips-input-min-width, 4rem);
    height: var(--combobox-chips-input-height, 1.75rem);
    margin: 0;
    padding: 0 var(--combobox-chips-input-padding-x, 0.5rem);
    border: 0;
    border-radius: var(--radius-sm);
    background: transparent;
    color: inherit;
    font: inherit;
    outline: 0;

    &::placeholder {
      color: var(--combobox-input-placeholder-color, var(--color-muted-foreground));
    }
  }

  .field {
    display: inline-flex;
    flex-direction: column;
    gap: var(--combobox-field-gap, 0.375rem);
  }

  .controlActions {
    position: absolute;
    right: var(--combobox-actions-offset-right, 0.5rem);
    top: 50%;
    display: inline-flex;
    align-items: center;
    gap: var(--combobox-actions-gap, 0.125rem);
    transform: translateY(-50%);
  }

  .itemText {
    grid-column-start: 2;
    min-width: 0;
    overflow: hidden;
  }

  .chipText {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .inlineInputContainer {
    box-sizing: border-box;
    padding: var(--spacing-2);
    border-bottom: var(--border-width-sm) solid var(--combobox-border-color, var(--color-border));

    & > .input {
      padding-inline: 0.75rem;
      border: var(--border-width-sm) solid var(--combobox-border-color, var(--color-border));
      border-radius: var(--radius-sm);
    }
  }
}
